import React, { useState } from 'react';

const Membership = () => {
  const [paymentMethod, setPaymentMethod] = useState('applepay');
  const [paymentSuccess, setPaymentSuccess] = useState(false);
  const [processing, setProcessing] = useState(false);
  const [cardNumber, setCardNumber] = useState('');

  const handleApplePay = async () => {
    if (!window.ApplePaySession) {
      alert('此浏览器不支持 Apple Pay');
      return;
    }

    setProcessing(true);
    try {
      const response = await fetch('http://localhost:8080/api/payment/apple-pay', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ token: 'apple_pay_token', amount: 3999 }),
      });
      const data = await response.json();
      if (data.success) {
        setPaymentSuccess(true);
      } else {
        alert('支付失败');
      }
    } catch (error) {
      alert('支付失败');
    }
    setProcessing(false);
  };

  const handleUnionPay = async () => {
    if (!cardNumber || cardNumber.length < 16) {
      alert('请输入有效的银联卡号');
      return;
    }

    setProcessing(true);
    try {
      const response = await fetch('http://localhost:8080/api/payment/unionpay', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ cardNumber, amount: 3999 }),
      });
      const data = await response.json();
      if (data.success) {
        setPaymentSuccess(true);
      } else {
        alert('支付失败');
      }
    } catch (error) {
      alert('支付失败');
    }
    setProcessing(false);
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h1 style={styles.title}>开通会员</h1>
        <div style={styles.price}>
          <span style={styles.priceAmount}>¥39.99</span>
          <span style={styles.pricePeriod}>/月</span>
        </div>
        <ul style={styles.features}>
          <li>✓ 解锁所有付费文章</li>
          <li>✓ 无广告阅读体验</li>
          <li>✓ 优先评论通知</li>
          <li>✓ 专属会员标识</li>
        </ul>

        <div style={styles.paymentMethods}>
          <button
            style={paymentMethod === 'applepay' ? styles.methodBtnActive : styles.methodBtn}
            onClick={() => setPaymentMethod('applepay')}
          >
             Apple Pay
          </button>
          <button
            style={paymentMethod === 'unionpay' ? styles.methodBtnActive : styles.methodBtn}
            onClick={() => setPaymentMethod('unionpay')}
          >
            🏦 银联卡
          </button>
        </div>

        {paymentMethod === 'applepay' && (
          <div style={styles.paymentSection}>
            <div style={styles.paymentInfo}>
              <p style={styles.paymentText}>使用 Apple Pay 支付</p>
              <p style={styles.paymentSubtext}>安全、快速、便捷</p>
            </div>
            <button
              style={styles.payBtn}
              onClick={handleApplePay}
              disabled={processing}
            >
              {processing ? '处理中...' : ' Pay'}
            </button>
          </div>
        )}

        {paymentMethod === 'unionpay' && (
          <div style={styles.paymentSection}>
            <div style={styles.paymentInfo}>
              <p style={styles.paymentText}>使用银联卡支付</p>
              <p style={styles.paymentSubtext}>支持所有银联卡</p>
            </div>
            <input
              type="text"
              placeholder="请输入银联卡号"
              value={cardNumber}
              onChange={(e) => setCardNumber(e.target.value)}
              style={styles.input}
              maxLength="19"
            />
            <button
              style={styles.payBtn}
              onClick={handleUnionPay}
              disabled={processing}
            >
              {processing ? '处理中...' : '立即支付'}
            </button>
          </div>
        )}

        {paymentSuccess && (
          <div style={styles.successSection}>
            <div style={styles.successIcon}>✓</div>
            <p style={styles.successText}>支付成功！会员已开通</p>
          </div>
        )}
      </div>
    </div>
  );
};

const styles = {
  container: {
    minHeight: 'calc(100vh - 200px)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    padding: '2rem',
  },
  card: {
    background: '#fff',
    padding: '3rem',
    borderRadius: '12px',
    boxShadow: '0 4px 16px rgba(0,0,0,0.1)',
    width: '100%',
    maxWidth: '500px',
    textAlign: 'center',
  },
  title: {
    fontSize: '2rem',
    marginBottom: '2rem',
    color: '#111827',
  },
  price: {
    marginBottom: '2rem',
  },
  priceAmount: {
    fontSize: '3rem',
    fontWeight: 'bold',
    color: '#fbbf24',
  },
  pricePeriod: {
    fontSize: '1.5rem',
    color: '#6b7280',
  },
  features: {
    listStyle: 'none',
    textAlign: 'left',
    marginBottom: '2rem',
    padding: '0 2rem',
  },
  paymentMethods: {
    display: 'flex',
    gap: '1rem',
    marginBottom: '2rem',
  },
  methodBtn: {
    flex: 1,
    padding: '1rem',
    border: '2px solid #e5e7eb',
    borderRadius: '8px',
    background: '#fff',
    cursor: 'pointer',
    fontSize: '1rem',
    transition: 'all 0.3s',
  },
  methodBtnActive: {
    flex: 1,
    padding: '1rem',
    border: '2px solid #667eea',
    borderRadius: '8px',
    background: '#f0f4ff',
    cursor: 'pointer',
    fontSize: '1rem',
    fontWeight: 'bold',
  },
  paymentSection: {
    marginBottom: '1rem',
  },
  paymentInfo: {
    textAlign: 'center',
    marginBottom: '1rem',
    padding: '1rem',
    background: '#f9fafb',
    borderRadius: '8px',
  },
  paymentText: {
    fontSize: '1rem',
    fontWeight: 'bold',
    marginBottom: '0.25rem',
  },
  paymentSubtext: {
    fontSize: '0.875rem',
    color: '#6b7280',
  },
  input: {
    width: '100%',
    padding: '1rem',
    marginBottom: '1rem',
    border: '2px solid #e5e7eb',
    borderRadius: '8px',
    fontSize: '1rem',
    boxSizing: 'border-box',
  },
  payBtn: {
    width: '100%',
    padding: '1rem',
    background: '#000',
    color: '#fff',
    border: 'none',
    borderRadius: '8px',
    fontSize: '1.1rem',
    fontWeight: 'bold',
    cursor: 'pointer',
  },
  successSection: {
    marginTop: '2rem',
    padding: '2rem',
    background: '#d1fae5',
    borderRadius: '8px',
    textAlign: 'center',
  },
  successIcon: {
    fontSize: '3rem',
    color: '#10b981',
    marginBottom: '0.5rem',
  },
  successText: {
    color: '#065f46',
    fontSize: '1.1rem',
    fontWeight: 'bold',
  },
};

export default Membership;
